import{c as i,W as p,j as s,m as a}from"./chunks/framework.CoQR5MuA.js";const _=JSON.parse('{"title":"赞比亚重点熟知事项","description":"赞比亚国情资料 — 赞比亚重点熟知事项","frontmatter":{"title":"赞比亚重点熟知事项","description":"赞比亚国情资料 — 赞比亚重点熟知事项"},"headers":[],"relativePath":"mining/zambia/zh/key-notes.md","filePath":"mining/zambia/zh/key-notes.md","lastUpdated":1780319686000}'),r={name:"mining/zambia/zh/key-notes.md"};function e(n,t,o,c,l,d){return p(),s("div",null,[...t[0]||(t[0]=[a('<h1 id="赞比亚重点熟知事项" tabindex="-1">赞比亚重点熟知事项 <a class="header-anchor" href="#赞比亚重点熟知事项" aria-label="Permalink to &quot;赞比亚重点熟知事项&quot;">​</a></h1><div class="reading-prose"><p>**6.**<strong>政府机构</strong></p><p>赞比亚政府实行总统内阁制。内阁由总统、副总统和30名部长组成。主要部委为：国防部、司法部、财政部、发展规划部、内政部、卫生部、外交部、农业部、渔业与畜牧业部、青年与体育部、商业/贸易与工业部、矿业与矿产发展部、能源部、信息与广播部、劳动与社会保障部、高等教育部、普通教育部、土地/自然资源与环境保护部、地方政府部、社区发展部与社会福利部、酋长与传统事务部、旅游与艺术部、交通与通信部、工程与供应部、住房与基础设施发展部、性别部、总统事务部、水利与环境保护部、国民指导与宗教事务部、副总统办公室部。</p><p>其他重要经济部门包括国家税务局、粮食储备署、赞比亚发展署、赞比亚银行（央行）、能源管理委员会等。</p><p><strong>【<strong><strong>医疗保险</strong></strong>】</strong></p><p>首都卢萨卡有全国最大的公立医院：赞比亚大学教学医院（UTH）紧急救助电话：00260-211-251451。援赞医疗队所在的利维·姆瓦纳瓦萨医院和援赞军医组所在的三军总医院也能为患重大疾病的中国公民提供紧急救助。</p><p>在铜带省基特韦市，赞中经贸合作区所属的中赞友谊医院拥有中国医生和一定的医疗条件。当地保险业有一定规模。中国公民和企业可自行选择保险经纪公司购买人身或医疗保险。</p><p><strong>铜带省</strong></p><p>铜带省，赞比亚中北部的省，邻民主刚果（扎伊尔）沙巴区。面积3.13万平方公里。人口1,581,221（2000年）。首府恩多拉。大部属非洲中部加丹加高原东段，海拔1，000米以上。</p><p>地表经长期侵蚀割切，形成一系列兀立的山脊和条状凹槽，古老岩层广泛出露。在古砂岩中富藏以铜为主的多金属矿物。热带草原气候，年降水量1，200—1，300毫米。卡富埃河及其支流流贯全境。</p><p>世界闻名的铜带的一部分，矿区自西北向东南断续延伸，长220余公里，宽65公里。除铜外，伴生有丰富的钴、硒、铀、金、银等。有恩昌加、穆富利拉、恩卡纳等大矿和恩多拉、基特韦、钦戈拉、卢安夏等冶炼中心和工业城市。有炼油、机械、水泥、食品等工业。</p><p>全省共分10个县:</p><p>奇利拉隆布韦县 (Chililalombwe District)</p><p>钦戈拉县(Chingola District)</p><p>卡卢卢希县(Kalulushi District)</p><p><strong>基特韦县(Kitwe District)</strong></p><p>卢安夏县(Luanshya District)</p><p>卢富万亚马县 (Lufwanyama District)</p><p>马塞塔县 (Masaita District)</p><p>姆彭戈韦县 (Mpongwe District)</p><p>穆富利拉县(Mufulira District)</p><p><strong>恩多拉县(Ndola District)</strong></p></div>',2)])])}const m=i(r,[["render",e]]);export{_ as __pageData,m as default};
